const resumeProfile = {
  name: 'Nikhil',
  currentTitle: 'Fresher - Computer Science Engineer',
  experienceYears: 0,
  skills: [
    'React', 'JavaScript', 'HTML', 'CSS', 'Tailwind CSS',
    'Node.js', 'Spring Boot', 'REST APIs',
    'MongoDB', 'MySQL',
    'Java', 'Python',
    'Git', 'Postman',
    'Machine Learning', 'NLP', 'RAG', 'LLM'
  ],
  preferredRoles: [
    'Junior Frontend Developer',
    'Junior Full Stack Developer',
    'React Developer Fresher',
    'Junior Java Developer',
    'Software Engineer Fresher',
    'Graduate Software Engineer'
  ],
  locations: ['Hyderabad', 'Bangalore', 'Remote']
};

const searchQueries = [];

for (const role of resumeProfile.preferredRoles) {
  for (const loc of resumeProfile.locations) {
    searchQueries.push({
      query: role + ' ' + loc,
      role: role,
      location: loc,
      skills: resumeProfile.skills,
      resumeSummary: 'Fresher B.Tech CSE (AI & ML) graduate with hands-on project experience in React, Spring Boot, Node.js, MongoDB, MySQL. Built 3 full-stack projects including a coding platform, e-commerce site, and movie booking system. AI/ML knowledge including NLP and RAG. Looking for entry-level software developer roles.'
    });
  }
}

return searchQueries.map(function(q) {
  return { json: q };
});

const items = [];

for (const item of $input.all()) {
  const data = item.json;

  // Handle SerpAPI response
  if (data.jobs_results && Array.isArray(data.jobs_results)) {
    for (const job of data.jobs_results) {
      items.push({
        title: job.title || 'No Title',
        company: job.company_name || 'Unknown',
        location: job.location || 'Not specified',
        description: job.description || '',
        link: job.share_link || '',
        source: 'Google Jobs',
        postedAt: job.detected_extensions?.posted_at || 'Recent',
        jobId: job.job_id || job.title + job.company_name
      });
    }
  }

  // Handle Naukri/Apify response (array of jobs)
  if (Array.isArray(data)) {
    for (const job of data) {
      items.push({
        title: job.title || 'No Title',
        company: job.companyName || job.company || 'Unknown',
        location: job.location || 'Not specified',
        description: job.jobDescription || job.description || '',
        link: job.jdURL || job.url || '',
        source: 'Naukri',
        postedAt: job.createdDate || 'Recent',
        jobId: job.jobId || job.jdURL || job.title
      });
    }
  }

  // Handle single Naukri job object
  if (data.title && data.jdURL) {
    items.push({
      title: data.title || 'No Title',
      company: data.companyName || 'Unknown',
      location: data.location || 'Not specified',
      description: data.jobDescription || '',
      link: data.jdURL || '',
      source: 'Naukri',
      postedAt: data.createdDate || 'Recent',
      jobId: data.jobId || data.jdURL
    });
  }
}

// Deduplicate by jobId
const seen = new Set();
const unique = items.filter(function(job) {
  if (!job.jobId || seen.has(job.jobId)) return false;
  seen.add(job.jobId);
  return true;
});

if (unique.length === 0) {
  return [{ json: { error: 'No jobs found', raw: $input.all()[0]?.json } }];
}

return unique.map(function(job) {
  return { json: job };
});

const items = [];

for (const item of $input.all()) {
  const data = item.json;

  // Gemini response format
  const text = data?.candidates?.[0]?.content?.parts?.[0]?.text || '{}';

  let scoring = {};
  try {
    const clean = text.replace(/```json|```/g, '').trim();
    scoring = JSON.parse(clean);
  } catch(e) {
    scoring = { score: 0, verdict: 'SKIP', matched: [], missing: [], advice: '' };
  }

  items.push({
    json: {
      ...item.json,
      score: scoring.score || 0,
      matched: scoring.matched || [],
      missing: scoring.missing || [],
      verdict: scoring.verdict || 'SKIP',
      advice: scoring.advice || ''
    }
  });
}

return items;

const items = [];

for (const item of $input.all()) {
  const job = item.json;

  const prompt = `Score this job for Nikhil (fresher 2026, B.Tech CSE AI & ML).
Skills: React, JavaScript, Node.js, Spring Boot, MongoDB, MySQL, Java, Python, Git, Tailwind CSS
Looking for: Entry-level fresher developer roles

JOB:
Title: ${job.title || 'N/A'}
Company: ${job.company || 'N/A'}
Description: ${(job.description || '').slice(0, 400)}

Reply ONLY with valid JSON no extra text:
{"score":75,"matched":["React"],"missing":["Docker"],"verdict":"APPLY_NOW","advice":"Apply directly"}`;

  let scoring = {};

  try {
    const response = await $helpers.httpRequest({
      method: 'POST',
      url: 'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key=YOUR_GEMINI_API_KEY',
      headers: { 
        'Content-Type': 'application/json' 
      },
      body: JSON.stringify({
        contents: [{ 
          parts: [{ 
            text: prompt 
          }] 
        }]
      })
    });

    const rawText = response?.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
    const clean = rawText.replace(/```json/g, '').replace(/```/g, '').trim();
    scoring = JSON.parse(clean);

  } catch(e) {
    scoring = { 
      score: 0, 
      verdict: 'SKIP', 
      matched: [], 
      missing: [], 
      advice: 'Error scoring this job' 
    };
  }

  items.push({
    json: {
      title: job.title || '',
      company: job.company || '',
      location: job.location || '',
      description: job.description || '',
      link: job.link || '',
      source: job.source || '',
      postedAt: job.postedAt || '',
      score: scoring.score || 0,
      matched: scoring.matched || [],
      missing: scoring.missing || [],
      verdict: scoring.verdict || 'SKIP',
      advice: scoring.advice || ''
    }
  });
}

return items;
